implementation_sketch_runtime_c.fork_exec_pair_pseudocode:
HexaVal hexa_spawn(HexaVal cmd) {
  if (!HX_IS_STR(cmd)) return hexa_int(-1);
  int in_pipe[2], out_pipe[2];
  if (pipe(in_pipe) != 0)  { _set_exec_errno(errno); return hexa_int(-1); }
  if (pipe(out_pipe) != 0) { close(in_pipe[0]); close(in_pipe[1]); _set_exec_errno(errno); return hexa_int(-1); }
  pid_t pid = fork();
  if (pid < 0) { /* close all 4 fds */ _set_exec_errno(errno); return hexa_int(-1); }
  if (pid == 0) {
    dup2(in_pipe[0], 0); dup2(out_pipe[1], 1);
    close(in_pipe[0]); close(in_pipe[1]);
    close(out_pipe[0]); close(out_pipe[1]);
    execl("/bin/sh", "sh", "-c", HX_STR(cmd), (char*)NULL);
    _exit(127);
  }
  // parent
  close(in_pipe[0]); close(out_pipe[1]);
  int slot = _alloc_child_slot();  // grows table if needed
  if (slot < 0) { kill(pid, SIGKILL); waitpid(pid, NULL, 0); close(in_pipe[1]); close(out_pipe[0]); _set_exec_errno(EMFILE); return hexa_int(-1); }
  g_children[slot] = (HexaChild){pid, in_pipe[1], out_pipe[0], 1, 0, 0};
  return hexa_int(slot);
}

implementation_sketch_runtime_c.send_pseudocode:
HexaVal hexa_send(HexaVal h, HexaVal payload) {
  HexaChild* c = _live_child(HX_INT(h));
  if (!c || !HX_IS_STR(payload)) return hexa_int(-1);
  const char* buf = HX_STR(payload); size_t n = strlen(buf);
  ssize_t w = write(c->stdin_fd, buf, n);
  if (w < 0) { c->state = 2; _set_exec_errno(errno); return hexa_int(-1); }
  return hexa_int((long long)w);
}

implementation_sketch_runtime_c.recv_line_pseudocode:
HexaVal hexa_recv_line(HexaVal h, HexaVal timeout_ms) {
  HexaChild* c = _live_child(HX_INT(h));
  if (!c) { /* set status=3 */ return hexa_str(""); }
  long long tmo = HX_IS_INT(timeout_ms) ? HX_INT(timeout_ms) : 5000;
  // poll() with O_NONBLOCK off: read 1 byte at a time until '\n' or timeout.
  // Simpler v1: use select(stdout_fd, tmo) then blocking read up to '\n'.
  char* buf = malloc(4096); size_t cap=4096, len=0;
  long long t0 = _now_ms();
  while (1) {
    long long elapsed = _now_ms() - t0;
    if (elapsed >= tmo) { c->last_recv_status = 1; free(buf); return hexa_str(""); }
    fd_set rf; FD_ZERO(&rf); FD_SET(c->stdout_fd, &rf);
    struct timeval tv = { (tmo-elapsed)/1000, ((tmo-elapsed)%1000)*1000 };
    int s = select(c->stdout_fd+1, &rf, NULL, NULL, &tv);
    if (s <= 0) continue;  // timeout slice; loop checks total
    char ch; ssize_t r = read(c->stdout_fd, &ch, 1);
    if (r == 0) {  // EOF — child closed stdout
      int st; waitpid(c->pid, &st, WNOHANG);
      c->last_exit = WIFEXITED(st) ? WEXITSTATUS(st) : (WIFSIGNALED(st) ? 128+WTERMSIG(st) : -1);
      c->state = 2; c->last_recv_status = 2;
      free(buf); return hexa_str("");
    }
    if (r < 0) { c->last_recv_status = 2; free(buf); return hexa_str(""); }
    if (len+1 >= cap) { cap *= 2; buf = realloc(buf, cap); }
    buf[len++] = ch;
    if (ch == '\n') { buf[len] = '\0'; c->last_recv_status = 0; return hexa_str_own(buf); }
  }
}

implementation_sketch_runtime_c.close_pseudocode:
HexaVal hexa_close(HexaVal h) {
  HexaChild* c = _slot(HX_INT(h));
  if (!c || c->state == 0) return hexa_int(-1);
  if (c->stdin_fd  >= 0) { close(c->stdin_fd);  c->stdin_fd  = -1; }
  if (c->stdout_fd >= 0) { close(c->stdout_fd); c->stdout_fd = -1; }
  if (c->state == 1 && c->pid > 0) {
    kill(c->pid, SIGTERM);
    for (int i=0; i<10; i++) {  // 100ms grace, 10ms slices
      int st; pid_t r = waitpid(c->pid, &st, WNOHANG);
      if (r == c->pid) { c->last_exit = WIFEXITED(st)?WEXITSTATUS(st):(WIFSIGNALED(st)?128+WTERMSIG(st):-1); break; }
      _sleep_ms(10);
    }
    if (c->last_exit == 0 && /* not yet reaped */) { kill(c->pid, SIGKILL); waitpid(c->pid, NULL, 0); }
  }
  c->state = 0;  // slot becomes free (id still not recycled)
  return hexa_int(c->last_exit);
}

implementation_sketch_runtime_c.atexit_cleanup:
static void _hexa_child_atexit(void) {
  for (int i=0; i<g_children_cap; i++) {
    HexaChild* c = &g_children[i];
    if (c->state == 1 && c->pid > 0) {
      // mirror close() but with shorter grace — we're shutting down
      if (c->stdin_fd >= 0) close(c->stdin_fd);
      kill(c->pid, SIGTERM);
      _sleep_ms(50);
      kill(c->pid, SIGKILL);
      waitpid(c->pid, NULL, WNOHANG);
    }
  }
}
// Registered once via atexit(_hexa_child_atexit) inside hexa_init_env or first hexa_spawn() call.
